class Solution {
    public int possibleStringCount(String word, int k) {
        int n = word.length();
        int MOD = (int) (1e9 + 7);
        long res = 1;
        int count = 1;
        for (int i = 1; i < n; i++) {
            if (word.charAt(i) == word.charAt(i - 1)) {
                count++;
            } else {
                res = res * Math.max(1, count - 1) % MOD;
                count = 1;
            }
        }
        res = res * Math.max(1, count - 1) % MOD;
        long ans = 0;
        for (int i = k; i <= n; i++) {
            ans = (ans + comb(n - i + countSegments(word) - 1, countSegments(word) - 1, MOD)) % MOD;
        }
        return (int) ans;
    }

    private int countSegments(String word) {
        int count = 1;
        for (int i = 1; i < word.length(); i++) {
            if (word.charAt(i) != word.charAt(i - 1)) {
                count++;
            }
        }
        return count;
    }

    private long comb(int n, int k, int MOD) {
        if (k > n) return 0;
        long res = 1;
        for (int i = 0; i < k; i++) {
            res = res * (n - i) % MOD;
            res = res * modInverse(i + 1, MOD) % MOD;
        }
        return res;
    }

    private long modInverse(int a, int m) {
        long m0 = m;
        long y = 0, x = 1;
        if (m == 1) return 0;
        while (a > 1) {
            long q = a / m;
            long t = m;
            m = a % m;
            a = t;
            t = y;
            y = x - q * y;
            x = t;
        }
        if (x < 0) x += m0;
        return x;
    }
}
efficiency: HIGH
time complexity: O(n + k)
space complexity: O(1)
energy implications: LOW
explanation: The solution efficiently calculates the number of possible original strings by counting consecutive characters, computing combinations using modular arithmetic, and applying the stars and bars technique.
